+// ─── Walking animation frames ──────────────────────────────────────
+
+const KING_WALK_FRAMES = [
+  KING_SPRITE.map((line, i) => {
+    if (i >= 15 && i <= 17) {
+      // Move legs slightly forward/back for walk cycle
+      return line.replace(/p/g, 'P').replace(/P/g, 'p');
+    }
+    return line;
+  }),
+  KING_SPRITE.map((line, i) => {
+    if (i >= 15 && i <= 17) {
+      return line;
+    }
+    return line;
+  }),
+];
+
+const KNIGHT_WALK_FRAMES = [
+  KNIGHT_SPRITE.map((line, i) => {
+    if (i >= 14 && i <= 16) {
+      // Shift leg pixels right by 1 for step forward
+      let chars = line.split('');
+      if (chars[5] === 'M') { chars[5] = ' '; chars[6] = 'M'; }
+      if (chars[9] === 'M') { chars[9] = ' '; chars[10] = 'M'; }
+      return chars.join('');
+    }
+    return line;
+  }),
+  KNIGHT_SPRITE.map((line, i) => {
+    if (i >= 14 && i <= 16) {
+      // Shift leg pixels left by 1 for step back
+      let chars = line.split('');
+      if (chars[6] === 'M') { chars[6] = ' '; chars[5] = 'M'; }
+      if (chars[10] === 'M') { chars[10] = ' '; chars[9] = 'M'; }
+      return chars.join('');
+    }
+    return line;
+  }),
+];
+
+const HEALER_WALK_FRAMES = [
+  HEALER_SPRITE,
+  HEALER_SPRITE.map(line => line),
+];
+
+const SENTINEL_WALK_FRAMES = [
+  SENTINEL_SPRITE,
+  SENTINEL_SPRITE.map(line => line),
+];
+
+const NOBILITY_WALK_FRAMES = [
+  NOBILITY_SPRITE,
+  NOBILITY_SPRITE.map(line => line),
+];
+
+const SQUIRE_WALK_FRAMES = [
+  SQUIRE_SPRITE,
+  SQUIRE_SPRITE.map(line => line),
+];
+
+const SCRIBE_WALK_FRAMES = [
+  SCRIBE_SPRITE,
+  SCRIBE_SPRITE.map(line => line),
+];
+
+const JUDGE_WALK_FRAMES = [
+  JUDGE_SPRITE,
+  JUDGE_SPRITE.map(line => line),
+];
+
+const BLACKSMITH_WALK_FRAMES = [
+  BLACKSMITH_SPRITE,
+  BLACKSMITH_SPRITE.map(line => line),
+];
+
+const WALK_FRAMES_MAP: Record<CharacterType, string[][]> = {
+  king: KING_WALK_FRAMES,
+  knight: KNIGHT_WALK_FRAMES,
+  healer: HEALER_WALK_FRAMES,
+  sentinel: SENTINEL_WALK_FRAMES,
+  nobility: NOBILITY_WALK_FRAMES,
+  squire: SQUIRE_WALK_FRAMES,
+  scribe: SCRIBE_WALK_FRAMES,
+  judge: JUDGE_WALK_FRAMES,
+  blacksmith: BLACKSMITH_WALK_FRAMES,
+};
+
+const WALK_FRAME_DURATION = 150;
+
