+function updateMovement(cs: CharState, bounds: { x: number; y: number; w: number; h: number }, frame: number) {
+  const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist > 2) {
+    cs.moving = true;
+    cs.x += (dx / dist) * 0.4;
+    cs.y += (dy / dist) * 0.4;
+    // Advance walk frame index smoothly
+    if (frame % WALK_FRAME_DURATION === 0) {
+      cs.wf = (cs.wf + 1) % WALK_FRAMES_MAP['king'].length; // use length from any character as all have at least 2 frames
+    }
+    cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
+  } else {
+    cs.moving = false;
+    cs.wf = 0;
+    cs.idle--;
+    if (cs.idle <= 0) {
+      const mx = bounds.w * 0.15, my = bounds.h * 0.2;
+      cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
+      cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
+      cs.idle = 150 + Math.random() * 300;
+    }
+  }
+}
