+export function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number, y: number, s: number, frame: number,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const palette = PALETTE_MAP[type];
+  const cs = getCS(id, x, y);
+  const flipH = cs.dir === 'left';
+
+  // Determine sprite frame to draw based on state and movement
+  let spriteFrames: string[][] = IDLE_FRAMES_MAP[type];
+  let frameIndex = Math.floor(frame / IDLE_FRAME_DURATION) % spriteFrames.length;
+  if (cs.moving) {
+    spriteFrames = WALK_FRAMES_MAP[type] || IDLE_FRAMES_MAP[type];
+    frameIndex = cs.wf % spriteFrames.length;
+  }
+  const sprite = spriteFrames[frameIndex];
+
+  // Bobbing effect for idle or working states
+  const bob = !cs.moving && state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : !cs.moving && state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob;
+
+  // Drop shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + sprite.length * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  drawSpriteDef(ctx, sprite, palette, cs.x, drawY, s, flipH);
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+}
